import { useEffect, useState } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import { api } from "../api";

export default function ProductDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.getProduct(id)
      .then(data => setProduct(data))
      .catch(err => { console.error(err); navigate("/"); })
      .finally(() => setLoading(false));
  }, [id, navigate]);

  const handleDelete = async () => {
    if (!window.confirm("Удалить товар?")) return;
    try {
      await api.deleteProduct(id);
      navigate("/");
    } catch (err) {
      alert("Ошибка удаления: " + (err?.response?.data?.error || err.message));
    }
  };

  if (loading) return <div className="container">Загрузка...</div>;
  if (!product) return <div className="container">Товар не найден</div>;

  return (
    <div className="container">
      <Link to="/" className="btn" style={{ marginBottom: 20, display: "inline-block" }}>← Назад</Link>
      <div className="card" style={{ maxWidth: 500, margin: "0 auto" }}>
        <img src={product.image} alt={product.name} style={{ width: "100%", borderRadius: 8 }} />
        <h2>{product.name}</h2>
        <p><b>Категория:</b> {product.category}</p>
        <p>{product.description}</p>
        <p><b>Цена:</b> {product.price} ₽</p>
        <p><b>В наличии:</b> {product.stock}</p>
        <p>⭐ {product.rating}</p>
        <div className="card-actions">
          <button className="btn edit-btn" onClick={() => navigate(`/edit/${product.id}`)}>Редактировать</button>
          <button className="btn danger-btn" onClick={handleDelete}>Удалить</button>
        </div>
      </div>
    </div>
  );
}
